import sys, io, json, base64
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding="utf-8")

# The CSV content from the API response
b64 = ""

decoded = base64.b64decode(b64).decode('utf-8', errors='replace')
# Show relevant parts
lines = decoded.split('\n')
print(f"Total lines in CSV: {len(lines)}")

# Search for рация
for i, line in enumerate(lines):
    if 'рац' in line.lower() or 'рации' in line.lower() or 'Рац' in line:
        print(f"\nLine {i}: {line[:300]}")

# Also print the first few lines to understand structure
print("\n--- FIRST 5 LINES ---")
for line in lines[:5]:
    print(line[:200])
